import math
from collections import defaultdict
import random

class NGramModel:
    def __init__(self, n):
        self.n = n
        self.model = defaultdict(int)

    def train(self, data):
        for sentence in data:
            for i in range(len(sentence)):
                ngram = tuple(sentence[max(0, i - self.n + 1):i + 1])
                self.model[ngram] += 1

    def predict(self, sentence):
        total = 0
        for i in range(len(sentence)):
            ngram = tuple(sentence[max(0, i - self.n + 1):i + 1])
            total += math.log(self.model[ngram] / sum(self.model.values()))
        return total

def compute_perplexity(model, test_data):
